/* canCustTransferSchduleMapper.insertMspCanCustTrnsRslt */
INSERT INTO MSP_CAN_CUST_TRNS_RSLT (
	WORK_DT
	, SERVICE_TYPE
	, OPEN_TYPE
	, TRNS_CNT
	, REGST_ID
	, REGST_DTTM
) VALUES (
	TO_CHAR(SYSDATE, 'YYYYMMDD')
	, #{serviceType}
	, #{openType}
	, #{trnsCnt}
	, 'SYSTEM'
	, SYSDATE
)
